import type { ChartZoomConfig, ZoomChangeType } from './zoom.js';
/**
 * @public
 */
export type ZoomChangeHandler = (newStart: Date | number, newEnd: Date | number, type: ZoomChangeType) => void;
/**
 * The zoom domains for the x-axis
 * @public
 */
export interface ZoomRanges<T> {
    initialZoom?: T;
    currentZoom?: T;
}
/**
 * The zoom domains and onchange callback for the x-axis
 * @public
 */
export interface ZoomInteractions<T> extends ZoomRanges<T> {
    onZoomChange?: ZoomChangeHandler;
}
/**
 * API config for the chart interactions
 * @public
 */
export interface ChartInteractionsConfig {
    /** Zoom config */
    zoom?: ChartZoomConfig;
    /** Zoom X config */
    /**
     * @deprecated ZoomX is deprecated, please use `<[Chart].Zoom/>`  instead.
     */
    zoomX?: ChartZoomConfig;
    /** Panning config */
    pan?: ChartZoomConfig;
    /** Handler triggered when there is a change on the time domain caused by a zoom action */
    onZoomChange?: ZoomChangeHandler;
}
